CREATE TRIGGER [Authorization].[UserRole_History]ON [Authorization].[UserRole]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.UserRoleId IS NOT NULL AND d.UserRoleId IS NULL THEN 'I' 		WHEN i.UserRoleId IS NOT NULL AND d.UserRoleId IS NOT NULL THEN 'U' 		WHEN i.UserRoleId IS NULL AND d.UserRoleId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.UserRoleId = d.UserRoleId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.Authorization_UserRole([UserRoleId], [UserId], [RoleId], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [UserRoleId], [UserId], [RoleId], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.Authorization_UserRole([UserRoleId], [UserId], [RoleId], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [UserRoleId], [UserId], [RoleId], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND